def load_config():
    """加载配置"""
    config_path = "/home/wuying/.openclaw/skillconfig/ozon-accounts.json"
    if os.path.exists(config_path):
        with open(config_path, "r") as f:
            data = json.load(f)
            # 使用 account2 (释朴的店)
            accounts = data.get("accounts", {})
            return accounts.get("account2", {})
    return {}

